static void GetFixedTree(unsigned *ll_lengths, unsigned *d_lengths)
{
    size_t i;
    for (i = 0; i < 144; i++)
        ll_lengths[i] = 8;
    for (i = 144; i < 256; i++)
        ll_lengths[i] = 9;
    for (i = 256; i < 280; i++)
        ll_lengths[i] = 7;
